void solve(int CASE)
{
	ll len, a, b; cin >> len >> a >> b;
	ll g = Math::gcd(a, b);
	if (len % g) {
		cout << "No" << endl;
		return;
	}

	ll x0, y0;
	Math::exgcd(a, b, x0, y0);
	ll dx = b / g, dy = a / g;
	ll x1 = ((__int128)x0 * (len / g) % dx + dx) % dx;
	ll y1 = (len - (__int128)a * x1) / b;

	if (y1 < 0) {
		cout << "No" << endl;
		return;
	}

	var f = [&](__int128 mid)->__int128 {
		__int128 x = x1 + mid * dx, y = y1 - mid * dy;
		return max(x, y);
		};
	ll l = 0, r = y1 / dy;
	while (l < r) {
		ll mid = l + r >> 1;
		if (f(mid) > f(mid + 1))l = mid + 1;
		else r = mid;
	}

	cout << "Yes" << endl;
	cout << x1 + l * dx << ' ' << y1 - l * dy << endl;
	return;
}
